using GameLib.EventChannelSystem;using JTH.Scripts.Data;using JTH.Scripts.Domain;using JTH.Scripts.Domain.Clear;using JTH.Scripts.Domain.Placement;using JTH.Scripts.Domain.Rotation;using JTH.Scripts.Domain.Turn;using JTH.Scripts.Events;using Magnet.Contracts.BlockShapes;using Reflex.Attributes;using UnityEngine;namespace JTH.Scripts.Bootstrap{    /// <summary>    /// BoardSession·BlockPlacementService 생성, 부착 후 클리어·회전·Consume까지 턴 Domain을 처리한다.    /// </summary>    public sealed class BoardPlacementBootstrap : MonoBehaviour    {        [SerializeField] private EventChannelSO magnetGameChannel;        [SerializeField] private BoardConfigSO boardConfig;        [Inject] private readonly BlockSpawnBootstrap _blockSpawnBootstrap;        private BoardSession _session;        private BlockPlacementService _placementService;        private readonly SquareClearService _clearService = new();        private readonly BoardRotationService _rotationService = new();        public BoardSession Session => _session;        public BlockPlacementService PlacementService => _placementService;        /// <summary>Consume 호출용.</summary>        public BlockSpawnBootstrap BlockSpawn => _blockSpawnBootstrap;        public TurnResolutionResult TryConfirmPlacement(IBlockShape shape, Vector2Int startPivot, int slotIndex)        {            PlacementResult result = _placementService.TryPlace(shape, startPivot);            if (!result.Success)            {                return TurnResolutionResult.Create(result, ClearDetectionResult.None, boardRotated: false);            }            magnetGameChannel.RaiseEvent(MagnetGameEvents.BlockPlacedEvent.Init(                result.BlockId,                slotIndex,                shape.ShapeId,                result.FinalPivot,                result.CellPositions));            if (result.HasCellsOutsideBounds)            {                magnetGameChannel.RaiseEvent(MagnetGameEvents.BoundaryViolationEvent);            }            ClearDetectionResult clearResult = _clearService.DetectAndApply(_session);            RaiseSquareClearedEvents(clearResult);            _rotationService.RotateClockwise(_session);            magnetGameChannel.RaiseEvent(MagnetGameEvents.BoardRotatedEvent.Init(                BoardRotationService.DefaultDegreesClockwise));            _blockSpawnBootstrap.Consume(slotIndex);            return TurnResolutionResult.Create(result, clearResult, boardRotated: true);        }        private void Awake()        {            Debug.Assert(boardConfig != null, "[BoardPlacementBootstrap] BoardConfigSO is not assigned.", this);            Debug.Assert(_blockSpawnBootstrap != null, "[BoardPlacementBootstrap] BlockSpawnBootstrap was not injected.", this);            _session = new BoardSession(boardConfig.BoardSize);            _placementService = new BlockPlacementService(_session);        }        private void RaiseSquareClearedEvents(ClearDetectionResult clearResult)        {            for (int i = 0; i < clearResult.ClearedSquares.Count; i++)            {                ClearedSquareInfo square = clearResult.ClearedSquares[i];                magnetGameChannel.RaiseEvent(MagnetGameEvents.SquareClearedEvent.Init(                    square.SquareSize,                    scoreAwarded: 0,                    square.ClearedCells));            }        }    }}